#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id using direct serialization
        stream << packet_id;

        // Write username with prefix using prefixed adaptor
        stream << hexi::prefixed(username);

        // Write scores count + scores using prefixed adaptor
        stream << hexi::prefixed(scores);

        // Write metadata as null-terminated string using null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create an empty vector as the underlying buffer
    std::vector<uint8_t> buffer;

    // Create buffer_adaptor with the empty vector
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary_stream with the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Call the packet's serialise method through the stream
    packet.serialise(stream);

    // Return the populated vector
    return buffer;
}
```

## Key Implementation Points:

1. **Direct Serialization**: `packet_id` is serialized directly using `stream << packet_id`

2. **Prefixed String**: `username` is serialized with length prefix using `hexi::prefixed(username)`

3. **Prefixed Vector**: `scores` is serialized with count prefix using `hexi::prefixed(scores)`, which internally handles the count and elements

4. **Null-Terminated String**: `metadata` is serialized as null-terminated using `hexi::null_terminated(metadata)`

5. **Buffer Management**: The `buffer_adaptor` wraps the empty vector, and `binary_stream` handles the serialization through the adaptor

6. **Stream Usage**: The `serialise` method is called through the stream, which properly handles the serialization protocol

This implementation follows the exact specifications provided, using the appropriate Hexi library adaptors and following the required serialization order.

