    hexi::file_buffer fb(file_path);

    // Check if the file buffer was created successfully (no errors)
    if (!fb || fb.error()) {
        return {}; // Return empty vector on error
    }

    // Adjust header_size to not exceed available data
    size_t actual_size = header_size;
    if (actual_size > fb.size()) {
        actual_size = fb.size();
    }

    // Create a vector to store the header data
    std::vector<uint8_t> header_data(actual_size);

    // Use the copy method to copy header data without advancing read pointer
    if (actual_size > 0) {
        fb.copy(header_data.data(), actual_size);
    }

    // Return the vector containing the header preview
    return header_data;
}
