#include <cstdint>

template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, const std::vector<uint8_t>& data) {
    // Convert vector data to const void* and calculate byte length
    const void* data_ptr = static_cast<const void*>(data.data());
    size_t data_length = data.size() * sizeof(uint8_t);

    // Use static_buffer's write method to write data
    buffer.write(data_ptr, data_length);
}

template<size_t buffer_size = 1024>
std::vector<uint8_t> read_data_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_read) {
    // Create a vector to store the read data
    std::vector<uint8_t> result(bytes_to_read);

    // Use static_buffer's read method to read data into the vector
    if (bytes_to_read > 0) {
        void* result_ptr = static_cast<void*>(result.data());
        buffer.read(result_ptr, bytes_to_read);
    }

    return result;
}
```

