#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct CompactPacket {
    uint32_t packet_id;
    std::vector<std::string> tags;
    std::string data;
};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a binary_stream object for writing, using the buffer
    hexi::binary_stream stream(buffer);

    // Use the stream's operator<< with prefixed_varint adaptor for tags vector
    stream << hexi::prefixed_varint(packet.tags);

    // Use the stream's operator<< with prefixed_varint adaptor for data string
    stream << hexi::prefixed_varint(packet.data);

    // Return the buffer containing the serialized data
    return buffer;
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    CompactPacket packet;

    // Create a binary_stream object for reading from the input buffer
    hexi::binary_stream stream(buffer);

    // Use the stream's operator>> with prefixed_varint adaptor to read tags vector
    stream >> hexi::prefixed_varint(packet.tags);

    // Use the stream's operator>> with prefixed_varint adaptor to read data string
    stream >> hexi::prefixed_varint(packet.data);

    // Read packet_id directly (POD type)
    stream >> packet.packet_id;

    return packet;
}

